B.L3=new A.a5(B.m,["Nye begyndelser, spontanitet, eventyr og ubegr\xe6nset potentiale. Narren opfordrer dig til at tage springet med tillid.","Uforsigtighed, naivitet, risikabel adf\xe6rd. Du b\xf8r overveje konsekvenserne, f\xf8r du handler."],t.w)
B.Ls=new A.a5(B.m,["Manifestation, kreativ kraft, viljestyrke og handling. Du har alle v\xe6rkt\xf8jer til r\xe5dighed.","Manipulation, uudnyttet potentiale, bedrag. V\xe6r \xe6rlig over for dig selv om dine intentioner."],t.w)
B.Lt=new A.a5(B.m,["Intuition, ubevidst visdom, indre stemme og mystik. Lyt til din indre vejledning.","Undertrykt intuition, hemmeligheder, tilbageholdt information. Du ignorerer vigtige signaler."],t.w)
B.LA=new A.a5(B.m,["Frugtbarhed, overflod, natur og moderlig omsorg. En periode med v\xe6kst og kreativitet.","Kreativ blokering, afh\xe6ngighed, kv\xe6lende omsorg. Find balance mellem at give og modtage."],t.w)
B.KT=new A.a5(B.m,["Autoritet, struktur, stabilitet og faderlig beskyttelse. Tag kontrol over din situation.","Dominans, stivhed, manglende fleksibilitet. V\xe6r forsigtig med at v\xe6re for kontrollerende."],t.w)
B.La=new A.a5(B.m,["Tradition, spirituel vejledning, konformitet og uddannelse. S\xf8g visdom fra etablerede kilder.","Opr\xf8r mod konventioner, personlig frihed, uortodokse tilgange. Find din egen vej."],t.w)
