B.LI=new A.a5(B.m,["Sejr, viljestyrke, beslutsomhed og kontrol. Du har momentum til at n\xe5 dine m\xe5l.","Manglende retning, aggression, magtesl\xf8shed. Genvurder din kurs og find fokus."],t.w)
B.LG=new A.a5(B.m,["Indre styrke, mod, t\xe5lmodighed og medf\xf8lelse. Din indre kraft er din st\xf8rste ressource.","Selvtvivl, svaghed, usikkerhed. Find din indre l\xf8ve og st\xe5 fast."],t.w)
