B.LP=new A.a5(B.m,["Pludselig forandring, sammenbrud, \xe5benbaring og kaos. Det som virker \xf8del\xe6ggende, rydder vejen for noget bedre.","Frygt for forandring, forsinkelse af det uundg\xe5elige. Forandringen kommer \u2013 v\xe6r forberedt."],t.w)
